1	#pragma once
2	
3	#include <cstdint>
4	
5	namespace hybrid {
6	
7	enum class AarSize : uint8_t
8	{
9	  Bits32 = 2,
10	  Bits64 = 3,
11	  Bits128 = 4,
12	};
13	
14	constexpr auto regno_csr(uint16_t csr) -> uint16_t { return csr; }
15	constexpr auto regno_gpr(uint16_t i) -> uint16_t { return 0x1000u + i; }
16	constexpr auto regno_fpr(uint16_t i) -> uint16_t { return 0x1020u + i; }
17	constexpr auto regno_vector(uint16_t i) -> uint16_t { return 0x1040u + i; }
18	
19	constexpr auto access_register_command(uint16_t regno, AarSize size, bool write,
20	                                       bool postexec = false) -> uint32_t
21	{
22	  uint32_t cmd = 0;
23	  cmd |= (uint32_t(size) & 0x7u) << 20;
24	  if (postexec) cmd |= 1u << 18;
25	  cmd |= 1u << 17;
26	  if (write) cmd |= 1u << 16;
27	  cmd |= regno;
28	  return cmd;
29	}
