1	// ResumeDriver translates a hybrid_state_v1 into a sequence of DMI register
2	// ops against the RISC-V Debug Module. The orchestration is testable in
3	// isolation by injecting a recording bus.
4	
5	#include "hybrid/abstract_command.hpp"
6	#include "hybrid/program_buffer.hpp"
7	#include "hybrid/resume_driver.hpp"
8	#include "hybrid/state_abi.h"
9	
10	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
11	#include <doctest.h>
12	
13	#include <cstdint>
14	#include <deque>
15	#include <optional>
16	#include <vector>
17	
18	namespace {
19	
20	// DMI register addresses from RISC-V Debug Spec 1.0.
21	constexpr uint8_t kDmcontrol  = 0x10;
22	constexpr uint8_t kDmstatus   = 0x11;
23	constexpr uint8_t kAbstractcs = 0x16;
24	constexpr uint8_t kCommand    = 0x17;
25	constexpr uint8_t kData0      = 0x04;
26	constexpr uint8_t kData1      = 0x05;
27	
28	// CSR numbers from Debug Spec.
29	constexpr uint16_t kCsrDpc = 0x7B1;
30	
31	struct DmiOp
32	{
33	  enum class Kind
34	  {
35	    Write,
36	    Read,
37	  };
38	  Kind kind;
39	  uint8_t reg;
40	  uint32_t value;  // for writes only
41	};
42	
43	struct RecordingBus final : hybrid::DmiBus
44	{
45	  std::vector<DmiOp> ops;
46	
47	  // Test-controlled response values for reads.
48	  uint32_t dmstatus_value = 0;       // bit 9: allhalted, bit 17: allresumeack
49	  uint32_t abstractcs_value = 0;     // fallback when queue is empty
50	  std::deque<uint32_t> abstractcs_queue; // queued reads drain first
51	
52	  void write(uint8_t reg, uint32_t value) override
53	  {
54	    ops.push_back({DmiOp::Kind::Write, reg, value});
55	  }
56	
57	  auto read(uint8_t reg) -> uint32_t override
58	  {
59	    ops.push_back({DmiOp::Kind::Read, reg, 0});
60	    if (reg == kDmstatus) return dmstatus_value;
61	    if (reg == kAbstractcs) {
62	      if (!abstractcs_queue.empty()) {
63	        auto v = abstractcs_queue.front();
64	        abstractcs_queue.pop_front();
65	        return v;
66	      }
67	      return abstractcs_value;
68	    }
69	    return 0;
70	  }
71	};
72	
73	auto rv64_state(uint64_t pc, uint64_t x10) -> hybrid_state_v1
74	{
75	  hybrid_state_v1 s{};
76	  s.magic = HYBRID_STATE_MAGIC;
77	  s.version = HYBRID_STATE_VERSION;
78	  s.flags = HYBRID_FLAG_RV64;
79	  s.pc = pc;
80	  s.priv = 3;
81	  s.gpr[10] = x10;
82	  return s;
83	}
84	
85	auto find_write(const std::vector<DmiOp>& ops, uint8_t reg)
86	  -> std::vector<uint32_t>
87	{
88	  std::vector<uint32_t> values;
89	  for (const auto& op : ops)
90	    if (op.kind == DmiOp::Kind::Write && op.reg == reg)
91	      values.push_back(op.value);
92	  return values;
93	}
94	
95	auto count_writes_to(const std::vector<DmiOp>& ops, uint8_t reg) -> std::size_t
96	{
97	  std::size_t n = 0;
98	  for (const auto& op : ops)
99	    if (op.kind == DmiOp::Kind::Write && op.reg == reg) ++n;
100	  return n;
101	}
102	
103	}  // namespace
104	
105	TEST_CASE("resume halts the hart before any abstract command")
106	{
107	  RecordingBus bus;
108	  // dmstatus answers halted+resumeack so poll loops finish on the first read.
109	  bus.dmstatus_value = (1u << 9) | (1u << 17);
110	
111	  hybrid::ResumeDriver driver(bus);
112	  driver.resume(rv64_state(/*pc=*/0x80001000, /*x10=*/0xdeadbeef));
113	
114	  // The first write must prime dmactive (DM out of reset) BEFORE haltreq is
115	  // accepted; the second write must add haltreq while keeping dmactive set.
116	  REQUIRE(bus.ops.size() >= 2);
117	
118	  const auto& prime = bus.ops[0];
119	  CHECK(prime.kind == DmiOp::Kind::Write);
120	  CHECK(prime.reg == kDmcontrol);
121	  CHECK((prime.value & 1u) == 1u);                  // dmactive
122	  CHECK(((prime.value >> 31) & 1u) == 0u);          // haltreq NOT yet set
123	
124	  const auto& halt = bus.ops[1];
125	  CHECK(halt.kind == DmiOp::Kind::Write);
126	  CHECK(halt.reg == kDmcontrol);
127	  CHECK((halt.value & 1u) == 1u);                   // dmactive still set
128	  CHECK(((halt.value >> 31) & 1u) == 1u);           // haltreq
129	}
130	
131	TEST_CASE("resume programs x1..x31 via DATA0/DATA1 + COMMAND, skipping x0")
132	{
133	  RecordingBus bus;
134	  bus.dmstatus_value = (1u << 9) | (1u << 17);
135	
136	  auto s = rv64_state(0x80001000, 0xdeadbeef);
137	  for (int i = 0; i < 32; ++i) s.gpr[i] = 0xa00000000ULL + i;
138	
139	  hybrid::ResumeDriver driver(bus);
140	  driver.resume(s);
141	
142	  std::vector<uint32_t> cmds;
143	  for (const auto& op : bus.ops)
144	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand)
145	      cmds.push_back(op.value);
146	
147	  CHECK(cmds.size() >= 31);
148	
149	  for (int i = 1; i < 32; ++i) {
150	    const auto expect =
151	      hybrid::access_register_command(hybrid::regno_gpr(i),
152	                                      hybrid::AarSize::Bits64, /*write=*/true);
153	    CHECK(cmds[i - 1] == expect);
154	  }
155	
156	  for (const auto& cmd : cmds) {
157	    const uint16_t regno = cmd & 0xffffu;
158	    CHECK(regno != hybrid::regno_gpr(0));
159	  }
160	}
161	
162	TEST_CASE("resume writes DPC = state.pc")
163	{
164	  RecordingBus bus;
165	  bus.dmstatus_value = (1u << 9) | (1u << 17);
166	
167	  constexpr uint64_t pc = 0x12345678'9ABCDEF0ULL;
168	  hybrid::ResumeDriver driver(bus);
169	  driver.resume(rv64_state(pc, 0));
170	
171	  // Look for the COMMAND write that targets CSR DPC (regno=0x7B1).
172	  std::vector<std::size_t> dpc_cmd_indices;
173	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
174	    const auto& op = bus.ops[i];
175	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
176	        && (op.value & 0xffffu) == kCsrDpc) {
177	      dpc_cmd_indices.push_back(i);
178	    }
179	  }
180	  REQUIRE(dpc_cmd_indices.size() == 1);
181	
182	  // Immediately preceding writes must set DATA0=low32(pc), DATA1=high32(pc).
183	  const auto cmd_idx = dpc_cmd_indices[0];
184	  REQUIRE(cmd_idx >= 2);
185	  const auto& d0 = bus.ops[cmd_idx - 2];
186	  const auto& d1 = bus.ops[cmd_idx - 1];
187	  CHECK(d0.kind == DmiOp::Kind::Write);
188	  CHECK(d0.reg == kData0);
189	  CHECK(d0.value == uint32_t(pc & 0xffffffffu));
190	  CHECK(d1.kind == DmiOp::Kind::Write);
191	  CHECK(d1.reg == kData1);
192	  CHECK(d1.value == uint32_t((pc >> 32) & 0xffffffffu));
193	}
194	
195	TEST_CASE("resume issues resumereq after register programming")
196	{
197	  RecordingBus bus;
198	  bus.dmstatus_value = (1u << 9) | (1u << 17);
199	
200	  hybrid::ResumeDriver driver(bus);
201	  driver.resume(rv64_state(0x80001000, 0));
202	
203	  // The last DMCONTROL write must clear haltreq and set resumereq.
204	  const auto dmctl_writes = find_write(bus.ops, kDmcontrol);
205	  REQUIRE(dmctl_writes.size() >= 2);
206	  const auto last = dmctl_writes.back();
207	  CHECK((last & 1u) == 1u);                  // dmactive still on
208	  CHECK(((last >> 31) & 1u) == 0u);          // haltreq cleared
209	  CHECK(((last >> 30) & 1u) == 1u);          // resumereq set
210	}
211	
212	TEST_CASE("resume polls DMSTATUS for halted before programming registers")
213	{
214	  RecordingBus bus;
215	  bus.dmstatus_value = (1u << 9) | (1u << 17);
216	
217	  hybrid::ResumeDriver driver(bus);
218	  driver.resume(rv64_state(0x80001000, 0));
219	
220	  // At least one DMSTATUS read happened, and it occurred before the first
221	  // DATA0/DATA1 write.
222	  std::optional<std::size_t> first_dmstatus_read;
223	  std::optional<std::size_t> first_data_write;
224	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
225	    const auto& op = bus.ops[i];
226	    if (op.kind == DmiOp::Kind::Read && op.reg == kDmstatus
227	        && !first_dmstatus_read)
228	      first_dmstatus_read = i;
229	    if (op.kind == DmiOp::Kind::Write && op.reg == kData0 && !first_data_write)
230	      first_data_write = i;
231	  }
232	  REQUIRE(first_dmstatus_read);
233	  REQUIRE(first_data_write);
234	  CHECK(*first_dmstatus_read < *first_data_write);
235	}
236	
237	TEST_CASE("resume rejects a state with wrong magic")
238	{
239	  RecordingBus bus;
240	  hybrid::ResumeDriver driver(bus);
241	
242	  hybrid_state_v1 bad{};
243	  bad.version = HYBRID_STATE_VERSION;
244	  bad.magic = 0xDEADBEEFu;
245	  CHECK_THROWS(driver.resume(bad));
246	}
247	
248	TEST_CASE("resume issues exactly one COMMAND per programmed register")
249	{
250	  RecordingBus bus;
251	  bus.dmstatus_value = (1u << 9) | (1u << 17);
252	
253	  hybrid::ResumeDriver driver(bus);
254	  driver.resume(rv64_state(0x80001000, 0));
255	
256	  // x1..x31 + DPC at minimum (x0 skipped). We do not yet program FPR/CSR/V.
257	  CHECK(count_writes_to(bus.ops, kCommand) >= 32u);
258	}
259	
260	namespace {
261	
262	auto cmd_regnos(const std::vector<DmiOp>& ops) -> std::vector<uint16_t>
263	{
264	  std::vector<uint16_t> ns;
265	  for (const auto& op : ops)
266	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand)
267	      ns.push_back(static_cast<uint16_t>(op.value & 0xffffu));
268	  return ns;
269	}
270	
271	auto contains_regno(const std::vector<uint16_t>& ns, uint16_t regno) -> bool
272	{
273	  for (auto n : ns) if (n == regno) return true;
274	  return false;
275	}
276	
277	}  // namespace
278	
279	TEST_CASE("resume does NOT program FP/CSR/PMP via DM Abstract Commands; "
280	          "those fields are pass-through-merged at drain time instead")
281	{
282	  RecordingBus bus;
283	  bus.dmstatus_value = (1u << 9) | (1u << 17);
284	
285	  auto s = rv64_state(0x80001000, 0);
286	  s.flags  |= HYBRID_FLAG_FP;
287	  s.mstatus = 0x1800ULL;
288	  for (int i = 0; i < 32; ++i) s.fpr[i] = 0xf0000000ULL + i;
289	  for (int i = 0; i < HYBRID_PMP_CFG_NUM; ++i)  s.pmpcfg[i]  = 0xa0 + i;
290	  for (int i = 0; i < HYBRID_PMP_ADDR_NUM; ++i) s.pmpaddr[i] = 0xb0 + i;
291	
292	  hybrid::ResumeDriver driver(bus);
293	  driver.resume(s);
294	
295	  const auto ns = cmd_regnos(bus.ops);
296	  for (uint16_t i = 0; i < 32; ++i)
297	    CHECK_FALSE(contains_regno(ns, hybrid::regno_fpr(i)));
298	  for (uint16_t csr : {0x300, 0x341, 0x342, 0x343, 0x340,
299	                       0x302, 0x303, 0x344, 0x304, 0xb00, 0xb02, 0x180})
300	    CHECK_FALSE(contains_regno(ns, hybrid::regno_csr(csr)));
301	  for (uint16_t i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
302	    CHECK_FALSE(contains_regno(ns, hybrid::regno_csr(0x3a0 + i)));
303	}
304	
305	TEST_CASE("resume with HYBRID_FLAG_V restores vstart/vxsat/vxrm/vcsr via abstract commands")
306	{
307	  RecordingBus bus;
308	  bus.dmstatus_value = (1u << 9) | (1u << 17);
309	
310	  auto s = rv64_state(0x80001000, 0);
311	  s.flags |= HYBRID_FLAG_V;
312	  s.vstart = 4;
313	  s.vxsat  = 1;
314	  s.vxrm   = 2;
315	  s.vcsr   = 5;
316	
317	  hybrid::ResumeDriver driver(bus);
318	  driver.resume(s);
319	
320	  const auto ns = cmd_regnos(bus.ops);
321	  CHECK(contains_regno(ns, hybrid::regno_csr(0x008)));  // vstart
322	  CHECK(contains_regno(ns, hybrid::regno_csr(0x009)));  // vxsat
323	  CHECK(contains_regno(ns, hybrid::regno_csr(0x00A)));  // vxrm
324	  CHECK(contains_regno(ns, hybrid::regno_csr(0x00F)));  // vcsr
325	}
326	
327	TEST_CASE("resume with HYBRID_FLAG_V: V CSR abstract writes precede GPR writes")
328	{
329	  RecordingBus bus;
330	  bus.dmstatus_value = (1u << 9) | (1u << 17);
331	
332	  auto s = rv64_state(0x80001000, 0);
333	  s.flags  |= HYBRID_FLAG_V;
334	  s.vstart = 1;
335	
336	  hybrid::ResumeDriver driver(bus);
337	  driver.resume(s);
338	
339	  // x5/x6 are written as scratch for vsetvl inside the V block, so look for
340	  // x1 specifically -- it is always the first register in the GPR restore loop.
341	  std::optional<std::size_t> vstart_cmd_idx;
342	  std::optional<std::size_t> x1_restore_cmd_idx;
343	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
344	    const auto& op = bus.ops[i];
345	    if (op.kind != DmiOp::Kind::Write || op.reg != kCommand) continue;
346	    const auto regno = static_cast<uint16_t>(op.value & 0xFFFFu);
347	    if (!vstart_cmd_idx && regno == hybrid::regno_csr(0x008))
348	      vstart_cmd_idx = i;
349	    if (!x1_restore_cmd_idx && regno == hybrid::regno_gpr(1))
350	      x1_restore_cmd_idx = i;
351	  }
352	  REQUIRE(vstart_cmd_idx.has_value());
353	  REQUIRE(x1_restore_cmd_idx.has_value());
354	  CHECK(*vstart_cmd_idx < *x1_restore_cmd_idx);
355	}
356	
357	TEST_CASE("resume with HYBRID_FLAG_V: PB fallback when abstract vstart write fails")
358	{
359	  RecordingBus bus;
360	  bus.dmstatus_value = (1u << 9) | (1u << 17);
361	
362	  auto s = rv64_state(0x80001000, 0);
363	  s.flags  |= HYBRID_FLAG_V;
