366	  // With Tier-B, abstractcs reads before vstart's cmderr check:
367	  //   [1] x5 busy-poll, [2] x6 busy-poll,
368	  //   [3] exec_progbuf pre-cmderr, [4] exec_progbuf busy-poll,
369	  //   [5] exec_progbuf post-cmderr, [6] vstart abstract-write busy-poll,
370	  //   [7] vstart cmderr check <- kCmderr triggers PB fallback.
371	  constexpr uint32_t kCmderr = 0x7u << 8;
372	  bus.abstractcs_queue = {0u, 0u, 0u, 0u, 0u, 0u, kCmderr};
373	
374	  hybrid::ResumeDriver driver(bus);
375	  driver.resume(s);
376	
377	  // csrrw x0, vstart(0x008), x5 -- stage value in t0(x5), write to vstart via PB
378	  const uint32_t expected_pb0 = hybrid::encode_csrrw(0, 0x008, 5);
379	  bool found_pb0 = false;
380	  bool found_exec = false;
381	  for (const auto& op : bus.ops) {
382	    if (op.kind == DmiOp::Kind::Write && op.reg == hybrid::kProgbuf0
383	        && op.value == expected_pb0)
384	      found_pb0 = true;
385	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
386	        && op.value == hybrid::kExecProgbufCmd)
387	      found_exec = true;
388	  }
389	  CHECK(found_pb0);
390	  CHECK(found_exec);
391	}
392	
393	TEST_CASE("resume with HYBRID_FLAG_V: vsetvl PB fires with vl in x5, vtype in x6")
394	{
395	  RecordingBus bus;
396	  bus.dmstatus_value = (1u << 9) | (1u << 17);
397	
398	  auto s = rv64_state(0x80001000, 0);
399	  s.flags |= HYBRID_FLAG_V;
400	  s.vl    = 16;
401	  s.vtype = 0xC1;  // LMUL=1, SEW=64
402	
403	  hybrid::ResumeDriver driver(bus);
404	  driver.resume(s);
405	
406	  // Expect: write x5=vl, write x6=vtype, then exec vsetvl x0,x5,x6 in PB.
407	  const uint32_t expected_vsetvl = hybrid::encode_vsetvl(0, 5, 6);
408	  bool found_x5_vl    = false;
409	  bool found_x6_vtype = false;
410	  bool found_vsetvl   = false;
411	  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
412	    const auto& op = bus.ops[i];
413	    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand) {
414	      const uint16_t regno = static_cast<uint16_t>(op.value & 0xFFFFu);
415	      if (regno == hybrid::regno_gpr(5) && i >= 2) {
416	        const auto& d0 = bus.ops[i - 2];
417	        const auto& d1 = bus.ops[i - 1];
418	        if (d0.reg == kData0 && d0.value == uint32_t(s.vl & 0xFFFFFFFFu) &&
419	            d1.reg == kData1 && d1.value == uint32_t(s.vl >> 32))
420	          found_x5_vl = true;
421	      }
422	      if (regno == hybrid::regno_gpr(6) && i >= 2) {
423	        const auto& d0 = bus.ops[i - 2];
424	        const auto& d1 = bus.ops[i - 1];
425	        if (d0.reg == kData0 && d0.value == uint32_t(s.vtype & 0xFFFFFFFFu) &&
426	            d1.reg == kData1 && d1.value == uint32_t(s.vtype >> 32))
427	          found_x6_vtype = true;
428	      }
429	    }
430	    if (op.kind == DmiOp::Kind::Write && op.reg == hybrid::kProgbuf0
431	        && op.value == expected_vsetvl)
432	      found_vsetvl = true;
433	  }
434	  CHECK(found_x5_vl);
435	  CHECK(found_x6_vtype);
436	  CHECK(found_vsetvl);
437	}
