TEST_CASE("resume with HYBRID_FLAG_FP programs f0..f31 via Abstract Commands")
{
  RecordingBus bus;
  bus.dmstatus_value = (1u << 9) | (1u << 17);

  auto s = rv64_state(0x80001000, 0);
  s.flags  |= HYBRID_FLAG_FP;
  s.mstatus = 0x6000ULL;  // mstatus.FS = Dirty: FPRs are writable
  for (int i = 0; i < 32; ++i) s.fpr[i] = 0xf000000000000000ULL + i;

  hybrid::ResumeDriver driver(bus);
  driver.resume(s);

  const auto ns = cmd_regnos(bus.ops);
  for (uint16_t i = 0; i < 32; ++i)
    CHECK(contains_regno(ns, hybrid::regno_fpr(i)));
}

TEST_CASE("resume with HYBRID_FLAG_FP: mstatus written before FPR Abstract Commands")
{
  RecordingBus bus;
  bus.dmstatus_value = (1u << 9) | (1u << 17);

  auto s = rv64_state(0x80001000, 0);
  s.flags  |= HYBRID_FLAG_FP;
  s.mstatus = 0x6000ULL;
  s.fpr[0]  = 0xdeadbeefcafef00dULL;

  hybrid::ResumeDriver driver(bus);
  driver.resume(s);

  std::optional<std::size_t> mstatus_cmd_idx;
  std::optional<std::size_t> f0_cmd_idx;
  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
    const auto& op = bus.ops[i];
    if (op.kind != DmiOp::Kind::Write || op.reg != kCommand) continue;
    const auto regno = static_cast<uint16_t>(op.value & 0xFFFFu);
    if (!mstatus_cmd_idx && regno == hybrid::regno_csr(0x300))
      mstatus_cmd_idx = i;
    if (!f0_cmd_idx && regno == hybrid::regno_fpr(0))
      f0_cmd_idx = i;
  }
  REQUIRE(mstatus_cmd_idx.has_value());
  REQUIRE(f0_cmd_idx.has_value());
  CHECK(*mstatus_cmd_idx < *f0_cmd_idx);
}

TEST_CASE("resume with HYBRID_FLAG_FP: FPR writes carry the state value via DATA0/DATA1")
{
  RecordingBus bus;
  bus.dmstatus_value = (1u << 9) | (1u << 17);

  auto s = rv64_state(0x80001000, 0);
  s.flags  |= HYBRID_FLAG_FP;
  s.mstatus = 0x6000ULL;
  s.fpr[7]  = 0x0123456789ABCDEFULL;

  hybrid::ResumeDriver driver(bus);
  driver.resume(s);

  std::optional<std::size_t> f7_cmd_idx;
  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
    const auto& op = bus.ops[i];
    if (op.kind == DmiOp::Kind::Write && op.reg == kCommand
        && (op.value & 0xFFFFu) == hybrid::regno_fpr(7)) {
      f7_cmd_idx = i;
      break;
    }
  }
  REQUIRE(f7_cmd_idx.has_value());
  REQUIRE(*f7_cmd_idx >= 2);
  const auto& d0 = bus.ops[*f7_cmd_idx - 2];
  const auto& d1 = bus.ops[*f7_cmd_idx - 1];
  CHECK(d0.kind == DmiOp::Kind::Write);
  CHECK(d0.reg == kData0);
  CHECK(d0.value == uint32_t(s.fpr[7] & 0xFFFFFFFFu));
  CHECK(d1.kind == DmiOp::Kind::Write);
  CHECK(d1.reg == kData1);
  CHECK(d1.value == uint32_t(s.fpr[7] >> 32));
}

