TEST_CASE("drain_with_passthrough copies FP/CSR/V slots from input and "
          "freshly drains GPRs/PC from the DM")
{
  RecordingBus bus;
  bus.dmstatus_value = kDmstatusHaltedAndAcked;
  bus.regfile[hybrid::regno_csr(RD::kCsrDpc)] = 0x80001234ULL;
  for (uint16_t i = 0; i < 32; ++i)
    bus.regfile[hybrid::regno_gpr(i)] = 0x10000000ULL + i;

  hybrid_state_v1 input{};
  input.magic   = HYBRID_STATE_MAGIC;
  input.version = HYBRID_STATE_VERSION;
  input.flags   = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP | HYBRID_FLAG_V;
  input.priv    = 3;
  input.mstatus = 0x1800ULL;
  input.satp    = 0x8000000080000000ULL;
  for (int i = 0; i < 32; ++i) input.fpr[i] = 0xf000000000000000ULL + i;
  for (int i = 0; i < HYBRID_PMP_CFG_NUM; ++i)  input.pmpcfg[i]  = 0xa0 + i;
  for (int i = 0; i < HYBRID_PMP_ADDR_NUM; ++i) input.pmpaddr[i] = 0xb0 + i;
  input.vlenb = 64;
  for (std::size_t i = 0; i < sizeof(input.vreg); ++i) input.vreg[i] = i & 0xff;

  hybrid::StateDrain drain(bus);
  const auto state = drain.drain_with_passthrough(input);

  // Pass-through fields preserve input verbatim.
  CHECK((state.flags & HYBRID_FLAG_FP) != 0u);
  CHECK(state.mstatus == 0x1800ULL);
  CHECK(state.satp    == 0x8000000080000000ULL);
  for (int i = 0; i < 32; ++i)
    CHECK(state.fpr[i] == 0xf000000000000000ULL + uint64_t(i));
  CHECK(state.pmpcfg[5]  == uint64_t(0xa5));
  CHECK(state.pmpaddr[7] == uint64_t(0xb7));
  CHECK(state.vlenb == 64ULL);
  CHECK(state.vreg[100] == uint8_t(100));

  // GPRs/PC come from the DM read, not the input.
  for (int i = 1; i < 32; ++i)
    CHECK(state.gpr[i] == 0x10000000ULL + uint64_t(i));
  CHECK(state.pc == 0x80001234ULL);
}

