TEST_CASE("drain_with_passthrough with HYBRID_FLAG_FP: FP reads issued after GPR reads")
{
  RecordingBus bus;
  bus.dmstatus_value = kDmstatusHaltedAndAcked;

  hybrid_state_v1 input{};
  input.magic   = HYBRID_STATE_MAGIC;
  input.version = HYBRID_STATE_VERSION;
  input.flags   = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP;
  input.priv    = 3;

  hybrid::StateDrain drain(bus);
  (void) drain.drain_with_passthrough(input);

  std::optional<std::size_t> last_gpr_cmd;
  std::optional<std::size_t> first_fpr_cmd;
  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
    const auto& op = bus.ops[i];
    if (op.kind != DmiOp::Kind::Write || op.reg != RD::kCommand) continue;
    const uint16_t regno = op.value & 0xFFFFu;
    if (regno >= hybrid::regno_gpr(1) && regno <= hybrid::regno_gpr(31))
      last_gpr_cmd = i;
    if (!first_fpr_cmd
        && regno >= hybrid::regno_fpr(0) && regno <= hybrid::regno_fpr(31))
      first_fpr_cmd = i;
  }
  REQUIRE(last_gpr_cmd.has_value());
  REQUIRE(first_fpr_cmd.has_value());
  CHECK(*last_gpr_cmd < *first_fpr_cmd);
}

TEST_CASE("drain_with_passthrough without HYBRID_FLAG_FP: no FPR Abstract Commands issued")
{
  RecordingBus bus;
  bus.dmstatus_value = kDmstatusHaltedAndAcked;

  hybrid_state_v1 input{};
  input.magic   = HYBRID_STATE_MAGIC;
  input.version = HYBRID_STATE_VERSION;
  input.flags   = HYBRID_FLAG_RV64;  // no HYBRID_FLAG_FP
  input.priv    = 3;
  for (int i = 0; i < 32; ++i) input.fpr[i] = 0xdeadbeef00000000ULL + i;

  hybrid::StateDrain drain(bus);
  const auto state = drain.drain_with_passthrough(input);

  // No FPR COMMAND reads issued.
  for (const auto& op : bus.ops) {
    if (op.kind != DmiOp::Kind::Write || op.reg != RD::kCommand) continue;
    const uint16_t regno = op.value & 0xFFFFu;
    CHECK_FALSE(regno >= hybrid::regno_fpr(0) && regno <= hybrid::regno_fpr(31));
  }

  // FPR slots remain pass-through from input (stale QEMU1 snapshot).
  for (int i = 0; i < 32; ++i)
    CHECK(state.fpr[i] == 0xdeadbeef00000000ULL + uint64_t(i));
}

