  bus.regfile[hybrid::regno_csr(RD::kCsrVstart)] = 7;
  bus.regfile[hybrid::regno_csr(RD::kCsrVxsat)]  = 1;
  bus.regfile[hybrid::regno_csr(RD::kCsrVxrm)]   = 2;
  bus.regfile[hybrid::regno_csr(RD::kCsrVcsr)]   = 5;
