TEST_CASE("drain_with_passthrough with HYBRID_FLAG_V: V CSR reads issued after GPR reads")
{
  RecordingBus bus;
  bus.dmstatus_value = kDmstatusHaltedAndAcked;

  hybrid_state_v1 input{};
  input.magic   = HYBRID_STATE_MAGIC;
  input.version = HYBRID_STATE_VERSION;
  input.flags   = HYBRID_FLAG_RV64 | HYBRID_FLAG_V;
  input.priv    = 3;

  hybrid::StateDrain drain(bus);
  (void) drain.drain_with_passthrough(input);

  // Find the last GPR COMMAND read and the first V CSR COMMAND read.
  std::optional<std::size_t> last_gpr_cmd;
  std::optional<std::size_t> first_vcsr_cmd;
  const std::initializer_list<uint16_t> vcsr_regnos = {
    hybrid::regno_csr(RD::kCsrVstart),
    hybrid::regno_csr(RD::kCsrVxsat),
    hybrid::regno_csr(RD::kCsrVxrm),
    hybrid::regno_csr(RD::kCsrVcsr),
    hybrid::regno_csr(RD::kCsrVtype),
    hybrid::regno_csr(RD::kCsrVl),
  };
  for (std::size_t i = 0; i < bus.ops.size(); ++i) {
    const auto& op = bus.ops[i];
    if (op.kind != DmiOp::Kind::Write || op.reg != RD::kCommand) continue;
    const uint16_t regno = op.value & 0xFFFFu;
    if (regno >= hybrid::regno_gpr(1) && regno <= hybrid::regno_gpr(31))
      last_gpr_cmd = i;
    for (uint16_t vcsr : vcsr_regnos)
      if (!first_vcsr_cmd && regno == vcsr)
        first_vcsr_cmd = i;
  }
  REQUIRE(last_gpr_cmd.has_value());
  REQUIRE(first_vcsr_cmd.has_value());
  CHECK(*last_gpr_cmd < *first_vcsr_cmd);
}

